1	/**
2	 * Minimal YAML parser for workflow structure tests.
3	 * Handles the subset of YAML needed for GitHub Actions workflows:
4	 * maps, sequences, scalars, multi-line strings.
5	 *
6	 * For production use you'd want js-yaml, but this avoids external deps.
7	 */
8	
9	interface YamlLine {
10	  indent: number;
11	  key?: string;
12	  value?: string;
13	  isListItem: boolean;
14	  raw: string;
15	}
16	
17	function tokenize(yaml: string): YamlLine[] {
18	  return yaml
19	    .split("\n")
20	    .filter((line) => {
21	      const trimmed = line.trim();
22	      return trimmed.length > 0 && !trimmed.startsWith("#");
23	    })
24	    .map((line) => {
25	      const indent = line.length - line.trimStart().length;
26	      const trimmed = line.trimStart();
27	      const isListItem = trimmed.startsWith("- ");
28	      const content = isListItem ? trimmed.slice(2) : trimmed;
29	
30	      const colonIdx = content.indexOf(": ");
31	      const endsWithColon = content.endsWith(":");
32	      let key: string | undefined;
33	      let value: string | undefined;
34	
35	      if (colonIdx > 0 && !content.startsWith("|")) {
36	        key = content.slice(0, colonIdx).trim();
37	        value = content.slice(colonIdx + 2).trim();
38	        if (value === "") value = undefined;
39	      } else if (endsWithColon && !content.includes(" ")) {
40	        key = content.slice(0, -1);
41	      } else if (!isListItem) {
42	        // bare scalar or complex key
43	        key = content;
44	      } else {
45	        value = content;
46	      }
47	
48	      return { indent, key, value, isListItem, raw: line };
49	    });
50	}
51	
52	/**
53	 * Parse a YAML string into a nested JS object.
54	 * Good enough for GHA workflow files — not a full YAML spec implementation.
55	 */
56	export function parse(yaml: string): Record<string, unknown> {
57	  const lines = tokenize(yaml);
58	  const result: Record<string, unknown> = {};
59	  parseBlock(lines, 0, 0, result);
60	  return result;
61	}
62	
63	function parseBlock(
64	  lines: YamlLine[],
65	  start: number,
66	  baseIndent: number,
67	  target: Record<string, unknown>
68	): number {
69	  let i = start;
70	
71	  while (i < lines.length) {
72	    const line = lines[i];
73	
74	    if (line.indent < baseIndent) break;
75	
76	    if (line.isListItem) break; // lists handled by parent
77	
78	    if (line.key) {
79	      const key = cleanKey(line.key);
80	
81	      if (line.value !== undefined) {
82	        // Simple key: value
83	        target[key] = cleanValue(line.value);
84	        i++;
85	      } else {
86	        // Key with nested content — look at next line
87	        if (i + 1 < lines.length) {
88	          const next = lines[i + 1];
89	          if (next.indent > line.indent && next.isListItem) {
90	            // List
91	            const arr: unknown[] = [];
